import 'package:flutter/material.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthenticationManager {
  final FlutterSecureStorage _secureStorage;
  final SharedPreferences _prefs;

  AuthenticationManager(this._secureStorage, this._prefs);

  Future<void> login(String token, String userData) async {
    await _secureStorage.write(key: 'authToken', value: token);
    await _prefs.setString('userData', userData);
  }

  Future<String?> getAuthToken() async {
    return await _secureStorage.read(key: 'authToken');
  }

  Future<String?> getUserData() async {
    return await _prefs.getString('userData');
  }

  Future<void> logout() async {
    await _secureStorage.delete(key: 'authToken');
    await _prefs.remove('userData');
  }
}

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  final AuthenticationManager authManager = AuthenticationManager(
    FlutterSecureStorage(),
    SharedPreferences.getInstance(),
  );

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(title: Text('Authentication Manager')),
        body: Center(
          child: FutureBuilder<String?>(
            future: authManager.getAuthToken(),
            builder: (context, snapshot) {
              if (snapshot.connectionState == ConnectionState.done) {
                if (snapshot.hasData && snapshot.data != null) {
                  return Text('Logged in');
                } else {
                  return ElevatedButton(
                    onPressed: () async {
                      await authManager.login('your_token', 'your_user_data');
